VALUES
  ('heelevel3-c8735cdb-moex-00009', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '民法中關於權利主體「自然人」之規定，下列敘述，何者正確？', '["某藝人以「小香瓜」為藝名，因其非真名，不受民法有關姓名權規定之保護", "甲與乙同時遇難，不能證明死亡先後時，視為同時死亡", "丙因失蹤多時生死不明，被妻子依法聲請法院宣告其死亡。但丙實則仍生存中，卻因已受死亡 宣告，所以權利能力及行為能力均為消滅", "丁開車闖紅燈撞上正在過馬路之孕婦戊，致其胎兒受傷。戊為胎兒之法定代理人，固得代為受 領丁給付之賠償金，但若嗣後胎兒死產，該受領之賠償金應返還丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00010', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲依民法規定發起設立A學術性社團法人，並將其主事務所設於臺中市。依民法規定，A法人應 向何主管機關登記，始得成立？', '["臺中市政府", "臺中地方法院", "內政部", "教育部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00011', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲80歲，罹輕度失智症，配偶已歿，有子女乙、丙、丁，平日由女兒乙照顧，乙擔心甲因心智缺 陷，而面臨不必要之法律糾紛，遂向法院聲請為甲為輔助宣告，法院經審查對甲為輔助宣告，並 以乙為甲之輔助人。下列甲之行為，何者須先取得輔助人乙之同意？', '["甲與好友相約到餐廳吃飯", "甲在好友A、B偕同下到C公證人處，在A、B、C見證下自書遺囑，就其法定繼承人乙、丙、 丁為遺產分配各得1/2、1/4、1/4", "甲因開車造成D受傷，自行與D成立和解契約，願意理賠D之身體傷害新臺幣（下同）50萬元", "甲自行到某百貨公司購買價錢1萬元之手錶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00012', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者錯誤？', '["債務人或第三人提供其不動產為擔保", "得擔保不確定或概括債權，例如約定擔保債權人與債務人間「現在及將來一切債務及其利息、 遲延利息、違約金、實行抵押權費用」", "得擔保一定範圍內之不特定債權", "所擔保之債權，應受最高額度限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00013', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '受有概括委任之受任人，為下列何種行為，不須有委任人之特別授權？', '["設定土地之普通抵押權", "贈與動產", "訂立二年之房屋租約", "訂立和解契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00014', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲將其所有之A屋出租於乙後，乙將其對A屋之租賃權讓與丙，並通知甲該情事。下列敘述，何 者正確？', '["如甲、乙間並無禁止轉讓之特約，乙之租賃權性質上並非不得讓與之債權", "如乙未能取得甲之同意移轉租賃權時，乙對丙應負債務不履行責任", "丙得以已通知甲關於A屋租賃權之讓與事實，主張其受讓對甲發生效力", "乙、丙就使用A屋而應給付與甲之租金，負連帶責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00015', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲請乙大幅翻修其房屋，約定由甲供給材料，乙為其施作，完工後給付報酬若干。乙明知甲所提 供之材料有問題，足以發生重大瑕疵，卻故意不告知甲，又以特約免除乙修繕房屋之瑕疵擔保義 務。乙嗣於民國（下同）103年1月5日完工，甲於112年4月20日始發現瑕疵，旋即通知乙， 並於113年5月1日定相當期限訴請乙修補瑕疵。對此，乙主張其不負物之瑕疵擔保義務，甲又 已罹於瑕疵發見期間，甲並已逾越權利行使期間等語，以資抗辯。下列敘述，何者正確？', '["因有問題之材料，係由甲所提供，故甲無定相當期限請求乙修補瑕疵之權利", "免除乙修繕房屋之瑕疵擔保義務之特約，為有效", "甲發現瑕疵時，已罹於5年之瑕疵發見期間，故甲不得主張定相當期限請求乙修補瑕疵之權利", "乙提出甲訴請乙修補瑕疵已逾越權利行使期間之抗辯，屬有理由 23520"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00016', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲將自己所有之A屋出售於乙，雙方約定簽約1個月後交屋，交屋後10日內辦妥所有權移轉登 記。下列敘述，何者錯誤？', '["A屋交付於乙後，危險負擔即移轉於乙", "A屋移轉登記於乙之前，即使已經交付，乙仍未取得A屋之所有權，故乙不得承受A屋之利益", "甲乙得於買賣契約中約定，A屋之利益及危險，自A屋之所有權移轉登記於乙時，由乙承受及 負擔", "甲對於乙，應擔保A屋交付於乙時，無滅失或減少其價值之瑕疵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00017', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲向乙購買A藝術品，約定價金新臺幣（下同）10萬元，並由乙於翌日早上11點送貨到甲宅。 乙隔天囑咐其員工丙開車於約定時間送至甲宅，詎甲非因過失確診罹患重症昏迷，被送進加護病 房，而不在家。丙久候多時，又聯絡不上甲，只好將A藝術品運回。回程途中，貨車司機丁因酒 駕而追撞丙車，丙身受重傷，其運送之A藝術品因碰撞滅失。下列敘述，何者錯誤？', '["丙就其遭撞受重傷一事，不得向無過失之乙請求賠償", "乙得向甲請求支付價金10萬元", "甲於支付價金時，得向乙請求讓與其對丁之侵權行為損害賠償請求權", "甲非因過失而受領遲延，仍負受領遲延責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00018', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '出租人甲將自己所有之A屋，口頭與乙約定以每月租金新臺幣（下同）3萬元出租於乙。甲乙間 關於A屋之租賃契約，下列敘述，何者正確？', '["若甲與乙僅以口頭約定租期為30年，則甲乙間之租賃契約期限縮短為20年", "若甲與乙僅以口頭約定租期為3個月，則租賃期限屆滿後，乙仍為租賃物之使用收益，而甲不 即表示反對之意思者，視為合意更新租賃契約。更新後之租賃契約，期間仍為3個月", "若甲與乙僅以口頭約定租期為3個月，但甲一開始即言明，期滿後絕不續租，則3個月之租賃 期限屆滿後，縱使乙仍為租賃物之使用收益，亦不發生租賃契約默示更新之效果，租賃契約因 期間屆滿而終了", "若甲與乙僅以口頭約定租期為30年，則甲乙間之租賃契約無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL)
